import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { AccountFilter } from '../../includes';
import { accountActions, accountStrings } from '../../config';
import { monthSelections } from '../../../../../utils';

const style = theme => ({
    root: {
        margin : 10
    }
})
class _ExpenditureSheetHeaderComponent extends Component {
    constructor(props) {
        super(props);
        const date = new Date();
        this.state = {
            year : date.getFullYear(),
            month : date.getMonth() + 1,
            categoryId : "all"
        }
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [accountStrings.expendCategories] : expendCategories
        } = this.props;
        const {
            year, month, categoryId
        } = this.state;
        if(!expendCategories) 
            accountActions.getAccountExpenditureCategories()(dispatch);
        accountActions.getAccountExpenditures(year, month, categoryId)(dispatch);
    }
    filterComponents(year, month, categoryId, categories){
        if(categories)
            categories = [...categories, {_id : "all", name : "All"}];
        return [
            {
                type : "select",
                name : "Year",
                value : year, //should come from outside
                valueProp : "value",
                nameProp : "name",
                options : [
                    {name : "2010", value : 1},
                    {name : "2011", value : 2},
                ],
                onChange : e => console.log(e.target.value),
            },
            {
                type : "select",
                name : "Month",
                value : month, //should come from outside
                valueProp : "value",
                nameProp : "name",
                options : monthSelections,
                onChange : e => console.log(e.target.value),
            },
            {
                type : "select",
                name : "Category",
                value : categoryId, //should come from outside
                valueProp : "_id",
                nameProp : "name",
                options : categories,
                onChange : e => console.log(e.target.value),
            },
        ]
    }
    render() {
        const {
            classes,
            [accountStrings.expendCategories] : expendCategories,
        } = this.props;
        const {year, month, categoryId} = this.state;
        return (
            <div className={classes.root}>
                <AccountFilter
                    filterComponents={this.filterComponents(year, month, categoryId, expendCategories)}
                    applyBtnHandler={()=>{}}/>
                
            </div>
        );
    }
}


_ExpenditureSheetHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({accountReducer}) => ({    
    [accountStrings.expendCategories] : accountReducer[accountStrings.expendCategories],
    [accountStrings.accountExpenditures] : accountReducer[accountStrings.accountExpenditures],
})


export const ExpenditureSheetHeaderComponent = connect(mapStateToProps)(withStyles(style)(_ExpenditureSheetHeaderComponent));