import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { accountActions } from '../../actions';
import { accountStrings } from '../../config';
import { MyTable, EditableCellMapFormat, mainStageHeaderAction, mainStageHeaderStrings } from '../../../../includes';
import { AccountExpenditureHeader } from './AccountExpenditureHeader';


const style = theme => ({
    root: {
    }
})
class _ExpenditureCategories extends Component {
    constructor(props) {
        super(props);
        this.state={
            expendCategories : null,
            expendCategoriesUnusable : null,
        }
        const {dispatch} = props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                AccountExpenditureHeader
            ]
        })(dispatch);
        accountActions.getAccountExpenditureCategories()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [accountStrings.expendCategories] : expendCategories
        } = props;
        if(expendCategories && JSON.stringify(expendCategories) 
        !== JSON.stringify(state.expendCategoriesUnusable)){
            state.expendCategoriesUnusable = expendCategories;
            state.expendCategories = expendCategories;
        }else if (state.expendCategoriesUnusable &&
            JSON.stringify(expendCategories) 
            !== JSON.stringify(state.expendCategoriesUnusable)){
                state.expendCategoriesUnusable = expendCategories;
                state.expendCategories = expendCategories;
        }
        return state;
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    render() {
        let {
            classes,
            [accountStrings.expendEditMode] : editMode
        } = this.props;
        let {expendCategories} = this.state;
        let header = ["ID", "Name"];
        let dataMap = ["_id", "name"];
        if(true){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            expendCategories = 
                expendCategories ? 
                    [...expendCategories.map(
                        item=>({
                            ...item, editable : true,
                            delible : true
                        })
                    ), {new: true}] : 
                    [{new : true}]
        }
        console.log(this.props);
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    CellMap={this.cellMapFormat({
                        skipEdit: ["_id"],
                    })}
                    data={expendCategories}
                    />
            </div>
        );
    }
}


_ExpenditureCategories.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({accountReducer}) => ({
    [accountStrings.expendCategories] : accountReducer[accountStrings.expendCategories],
    [accountStrings.expendEditMode] : accountReducer[accountStrings.expendEditMode],
})


export const ExpenditureCategories = connect(mapStateToProps)(withStyles(style)(_ExpenditureCategories));