import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { accountStrings } from '../../config';
import { FormControl, Button } from '@material-ui/core';
import { colors } from '../../../../../utils';
import { accountActions } from '../../actions';


const style = theme => ({
    root: {
    },
    formControl : {
        margin : 10
    }
})
class _AccountExpenditureHeader extends Component {
    setTimeTableEditMode = ()=>{
        const {
            dispatch,
            [accountStrings.expendEditMode] : editMode
        } = this.props;
        accountActions.setExpenditureEditMode(!Boolean(editMode))(dispatch);
    }
    cancelEdit=()=>{
        const {dispatch} = this.props;
        accountActions.setExpenditureEditMode(false)(dispatch);
    }
    render() {
        const {
            classes,
            [accountStrings.expendEditMode] : editMode
        } = this.props;
        return (
            <div className={classes.root}>
                <FormControl 
                    className={classes.formControl}>
                    <Button 
                        variant="contained" style={{backgroundColor:colors.secondary}}
                        onClick={this.setTimeTableEditMode.bind(this)}>
                            {editMode ? "Save" : "Edit"}
                        </Button>
                </FormControl>
                {editMode && 
                    <FormControl className={classes.formControl}>
                        <Button 
                        color="secondary"
                        onClick={this.cancelEdit.bind(this)}>Cancel</Button>
                    </FormControl>}
            </div>
        );
    }
}
_AccountExpenditureHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({accountReducer}) => ({
    [accountStrings.expendEditMode] : accountReducer[accountStrings.expendEditMode],
})


export const AccountExpenditureHeader = connect(mapStateToProps)(withStyles(style)(_AccountExpenditureHeader));