import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, MyCustomTabs } from '../../../includes';
import { ExpenditureSheet } from './ExpenditureSheet';
import { ExpenditureCategories } from './ExpenditureCategories';
import { accountActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
    }
})

class _Expenditure extends Component {
    constructor(props) {
        super(props);
        this.state={
            tabValue : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "ACCOUNT (EXPENDITURE)",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Account (expenditure)", path : routeNamesSchool.accountExpenditure},
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);

        this.setComponentContext = this.setComponentContext.bind(this);
    }
    setTabValue=tabValue=>{
        const {dispatch} = this.props;
        this.setState({tabValue});
        accountActions.setExpenditureTabValue(tabValue)(dispatch);
    }
    setComponentContext=context=>{
        const {dispatch} = this.props;
        accountActions.setExpenditureTabComponent(context)(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    tabs={{
                        expend : "Expenditure",
                        cat : "Source",
                    }}
                    getInitialTabValue={this.setTabValue.bind(this)}
                    position="sticky"
                    />
                <div style={{marginTop : 20}}>
                    {tabValue === "cat" && <ExpenditureCategories
                        getContext={this.setComponentContext}/>}
                    {tabValue === "expend" && <ExpenditureSheet
                        getContext={this.setComponentContext}/>}
                </div>
            </div>
        );
    }
}


_Expenditure.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = state => ({
    state
})


export const Expenditure = connect(mapStateToProps)(withStyles(style)(_Expenditure));
export {Expenditure as default};